import { createClient } from '@supabase/supabase-js'
import { config } from 'dotenv'
config({ path: '.env.local' })

const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL!
const SUPABASE_KEY = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY)

function parseMoney(s: string): number {
  return parseFloat(s.replace(/[$,]/g, '')) || 0
}

function cleanName(name: string): string {
  // Remove encoding artifacts (â, â€¢ etc.) and trim
  return name.replace(/\s*â\s*$/, '').replace(/â/g, '').trim()
}

function guessInformalName(formalName: string): string {
  // Remove honorifics
  let name = formalName.replace(/^(Dr\.|Mr\.|Mrs\.|Ms\.|Rev\.)\s+/i, '')
  // If it's "First Last", return First
  // If it's "First & Second Last" or "First, Second & Third Last", keep the first-name part
  // Strip last name (last word) for simple cases
  const parts = name.split(/\s+/)
  if (parts.length === 2) return parts[0]
  // Handle "A & B Last" → "A & B"
  if (name.includes('&') || name.includes(',')) {
    // Drop last word (surname)
    return parts.slice(0, -1).join(' ')
  }
  return parts[0]
}

