async function run() {
  console.log(`Importing ${rawData.length} donors...`)

  for (const d of rawData) {
    const formalName = cleanName(d.name)
    const informalName = guessInformalName(formalName)

    // Insert donor
    const { data: donor, error: donorError } = await supabase
      .from('donors')
      .insert({
        formal_name: formalName,
        informal_first_name: informalName,
        address: d.address,
        historical_lifetime_giving: d.lifetime,
        historical_donation_count: d.count,
      })
      .select('id')
      .single()

    if (donorError) {
      console.error(`Failed to insert ${formalName}:`, donorError.message)
      continue
    }

    // Insert last gift as a donation record
    const { error: donationError } = await supabase.from('donations').insert({
      donor_id: donor.id,
      amount: d.lastGift,
      date: d.lastDate,
      type: 'one-time',
    })

    if (donationError) {
      console.error(`Failed to insert donation for ${formalName}:`, donationError.message)
    } else {
      console.log(`✓ ${formalName}`)
    }
  }

  console.log('\nImport complete.')
}

run().catch(console.error)
